// ============================================================================
// lib/googleWebClientId.generated.ts — 자동 생성(평문 하드코딩 금지) (Slice 5)
//
// 이 파일은 직접 편집하지 않는다. `node scripts/gen-google-web-client-id.js` 가
// android/app/google-services.json 의 웹 OAuth 클라이언트(oauth_client 중
// client_type === 3, 즉 R.string.default_web_client_id 와 동일한 값)에서 client_id 를
// 읽어 이 파일을 덮어쓴다.
//
// 웹 클라이언트 id 는 앱에 임베드되는 공개 식별자이지만, 시크릿 0 원칙을 지키려
// 생성 스크립트는 이 파일을 git skip-worktree 로 표시해 실제 값이 커밋되지 않게 한다.
// ============================================================================

/** 웹 OAuth 클라이언트 id(=default_web_client_id). 비어 있으면 Google 로그인 비활성. */
export const GOOGLE_WEB_CLIENT_ID = '';
